+function drawStoneTile(ctx: CanvasRenderingContext2D, tx: number, ty: number) {
+  // 16x16 gray stone block with mortar lines
+  const base = '#7a7a7a';
+  const mortar = '#c0c0c0';
+  ctx.fillStyle = base;
+  ctx.fillRect(tx, ty, 16, 16);
+
+  // Draw subtle noise pattern for stone texture
+  for (let i = 0; i < 20; i++) {
+    const x = tx + Math.floor(Math.random() * 14) + 1;
+    const y = ty + Math.floor(Math.random() * 14) + 1;
+    ctx.fillStyle = `rgba(120,120,120,${Math.random() * 0.15})`;
+    ctx.fillRect(x, y, 1, 1);
+  }
+
+  // Mortar lines on right and bottom edges
+  ctx.fillStyle = mortar;
+  ctx.fillRect(tx + 15, ty, 1, 16);
+  ctx.fillRect(tx, ty + 15, 16, 1);
+}
+
+function drawWoodTile(ctx: CanvasRenderingContext2D, tx: number, ty: number) {
+  // 16x16 horizontal wood plank with grain
+  const plankBase = '#6b4a2f';
+  const plankHighlight = '#8b6b4f';
+  const plankShadow = '#4a2f1a';
+
+  ctx.fillStyle = plankBase;
+  ctx.fillRect(tx, ty, 16, 16);
+
+  // Draw horizontal grain lines
+  for (let i = 2; i < 16; i += 3) {
+    ctx.strokeStyle = plankShadow;
+    ctx.beginPath();
+    ctx.moveTo(tx, ty + i + 0.5);
+    ctx.lineTo(tx + 16, ty + i + 0.5);
+    ctx.stroke();
+  }
+
+  // Draw knots as small ovals
+  ctx.fillStyle = plankHighlight;
+  for (let i = 3; i < 16; i += 7) {
+    const y = ty + i;
+    ctx.beginPath();
+    ctx.ellipse(tx + 5, y, 2, 1, 0, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.beginPath();
+    ctx.ellipse(tx + 11, y + 3, 2, 1, 0, 0, Math.PI * 2);
+    ctx.fill();
+  }
+}
+
+function drawCarpetTile(ctx: CanvasRenderingContext2D, tx: number, ty: number) {
+  // 16x16 red carpet tile with border pattern
+  const base = '#8b2020';
+  const border = '#6b1515';
+  const accent = '#a03030';
+
+  ctx.fillStyle = base;
+  ctx.fillRect(tx, ty, 16, 16);
+
+  // Draw border lines
+  ctx.fillStyle = border;
+  ctx.fillRect(tx, ty, 16, 2);
+  ctx.fillRect(tx, ty + 14, 16, 2);
+  ctx.fillRect(tx, ty, 2, 16);
+  ctx.fillRect(tx + 14, ty, 2, 16);
+
+  // Draw diamond accent in center
+  ctx.fillStyle = accent;
+  ctx.beginPath();
+  ctx.moveTo(tx + 8, ty + 4);
+  ctx.lineTo(tx + 12, ty + 8);
+  ctx.lineTo(tx + 8, ty + 12);
+  ctx.lineTo(tx + 4, ty + 8);
+  ctx.closePath();
+  ctx.fill();
+}
+
+function drawCobblestoneTile(ctx: CanvasRenderingContext2D, tx: number, ty: number) {
+  // 16x16 cobblestone tile with irregular circles
+  const base = '#5a5a5a';
+  const stone = '#7a7a7a';
+  const shadow = '#3a3a3a';
+
+  ctx.fillStyle = base;
+  ctx.fillRect(tx, ty, 16, 16);
+
+  // Draw 3 irregular stones as circles with shading
+  const stones = [
+    { x: tx + 5, y: ty + 5, r: 4 },
+    { x: tx + 11, y: ty + 6, r: 3 },
+    { x: tx + 9, y: ty + 11, r: 4 },
+  ];
+  stones.forEach(({ x, y, r }) => {
+    // Stone base
+    ctx.fillStyle = stone;
+    ctx.beginPath();
+    ctx.ellipse(x, y, r, r * 0.7, Math.random() * 0.3, 0, Math.PI * 2);
+    ctx.fill();
+
+    // Shadow on bottom right
+    const grad = ctx.createRadialGradient(x + r / 3, y + r / 3, r / 4, x + r / 3, y + r / 3, r);
+    grad.addColorStop(0, 'rgba(0,0,0,0.3)');
+    grad.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = grad;
+    ctx.beginPath();
+    ctx.ellipse(x, y, r, r * 0.7, Math.random() * 0.3, 0, Math.PI * 2);
+    ctx.fill();
+  });
+}
+
+function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  const ft: Record<CharacterType, string> = {
+    king: 'carpet', nobility: 'wood', knight: 'wood', squire: 'wood',
+    healer: 'cobblestone', sentinel: 'stone', scribe: 'wood', judge: 'wood', blacksmith: 'stone',
+  };
+  const tile = 16;
+  const kind = ft[type];
+
+  const cols = Math.ceil(w / tile);
+  const rows = Math.ceil(h / tile);
+
+  for (let r = 0; r < rows; r++) {
+    for (let c = 0; c < cols; c++) {
+      const tx = x + c * tile;
+      const ty = y + r * tile;
+      switch (kind) {
+        case 'stone':
+          drawStoneTile(ctx, tx, ty);
+          break;
+        case 'dark_stone':
+          // fallback to stone tile dark variant
+          drawStoneTile(ctx, tx, ty);
+          break;
+        case 'wood':
+          drawWoodTile(ctx, tx, ty);
+          break;
+        case 'carpet':
+          drawCarpetTile(ctx, tx, ty);
+          break;
+        case 'cobblestone':
+          drawCobblestoneTile(ctx, tx, ty);
+          break;
+        default:
+          // fallback fill
+          ctx.fillStyle = '#222';
+          ctx.fillRect(tx, ty, tile, tile);
+          break;
+      }
+    }
+  }
+
+  // Additional thematic floor decorations for carpet (border stripes)
+  if (kind === 'carpet') {
+    const cw = w * 0.35, cx = x + (w - cw) / 2;
+    ctx.fillStyle = '#6b1515'; ctx.fillRect(cx, y, cw, h);
+    ctx.fillStyle = '#8b2020'; ctx.fillRect(cx + 3, y, cw - 6, h);
+    ctx.fillStyle = P.gold[2];
+    ctx.fillRect(cx + 1, y, 2, h);
+    ctx.fillRect(cx + cw - 3, y, 2, h);
+    for (let dy = 0; dy < h; dy += 20) {
+      ctx.fillStyle = P.gold[1];
+      ctx.fillRect(cx + cw / 2 - 2, y + dy + 6, 4, 4);
+    }
+  }
+}
